import React, { useEffect, useState } from 'react';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './UserPages.module.css';

const PackagesPage = () => {
  const [packages, setPackages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState('');
  const [booking, setBooking] = useState(null); // packageId being booked

  useEffect(() => {
    api.get('/packages')
      .then((res) => setPackages(res.data?.data || []))
      .catch(() => setError('Failed to load packages.'))
      .finally(() => setLoading(false));
  }, []);

  const handleBook = async (pkgId) => {
    setBooking(pkgId);
    try {
      await api.post('/bookings', { package: pkgId });
      alert('Booking confirmed! 🎉');
    } catch (err) {
      alert(err.response?.data?.error || 'Booking failed.');
    } finally {
      setBooking(null);
    }
  };

  return (
    <>
      <Navbar />
      <div className={styles.page}>
        <h1>✈️ Tour Packages</h1>
        {loading && <p>Loading…</p>}
        {error   && <p style={{ color: 'red' }}>{error}</p>}
        {!loading && !error && (
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Package</th>
                <th>Destination</th>
                <th>Duration</th>
                <th>Price</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {packages.length === 0 ? (
                <tr><td colSpan={5}>No packages available.</td></tr>
              ) : packages.map((p) => (
                <tr key={p._id}>
                  <td>{p.name}</td>
                  <td>{p.destination?.name || '—'}</td>
                  <td>{p.duration} days</td>
                  <td>${p.price}</td>
                  <td>
                    <button
                      className={`${styles.btnSm} ${styles.btnPrimary}`}
                      onClick={() => handleBook(p._id)}
                      disabled={booking === p._id}
                    >
                      {booking === p._id ? 'Booking…' : 'Book Now'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </>
  );
};

export default PackagesPage;
